SELECT o.order_id AS orderId, o.customer_id AS customerId, c.customer_name AS customerName, c.address AS customerAddress, o.group_id AS groupId, g.name AS groupName, o.generation, o.order_type AS orderType, o.is_async AS isAsync, o.belong_company AS belongCompany, o.produce_company AS produceCompany, o.gen_no AS genNo, o.remark, o.create_by AS createBy, o.create_time AS createTime, o.order_status AS orderStatus, o.status_time AS statusTime FROM yk_order_info o LEFT JOIN yk_customer_info c ON o.customer_id = c.id LEFT JOIN yk_subject_group_info g ON o.group_id = g.id
AND o.order_id >= #{query.startOrderId}
AND o.order_id <= #{query.endOrderId}
AND o.create_by LIKE CONCAT('%', #{query.createBy}, '%')
AND o.create_time >= #{query.startTime}
AND o.create_time <= #{query.endTime}
AND o.belong_company LIKE CONCAT('%', #{query.belongCompany}, '%')
AND o.produce_company LIKE CONCAT('%', #{query.produceCompany}, '%')
ORDER BY o.create_time DESC
